package net.minecraft.item; public class ItemStack { public int stackSize; private final Item item; private int metadata,damage,maxDamage; private boolean enchanted; public ItemStack(Item item,int count){this.item=item;this.stackSize=count;} public Item getItem(){return item;} public int getMetadata(){return metadata;} public int getItemDamage(){return damage;} public int getMaxDamage(){return maxDamage;} public boolean isItemStackDamageable(){return maxDamage>0;} public boolean isItemEnchanted(){return enchanted;} }
